html:
{% set day = frappe.utils.formatdate(doc.transaction_date, "dd") if doc.transaction_date else "" %}
{% set month = frappe.utils.formatdate(doc.transaction_date, "MM") if doc.transaction_date else "" %}
{% set year = frappe.utils.formatdate(doc.transaction_date, "YYYY") if doc.transaction_date else "" %}

<style>
	@page { size: Letter; margin: 0.4in; }
	.print-format { font-family: "Times New Roman", serif; font-size: 10pt; }
</style>

<div class="print-format">
	<div>{{ day }}/{{ month }}/{{ year }}</div>
	<div>{{ doc.name }}</div>
</div>
